// ============================================================================
// miles-jira-work-items-handler · Validate & Route
// ----------------------------------------------------------------------------
// Gateway unico para operaciones CRUD sobre work items de Jira.
// Contrato de entrada (POST /webhook/jira-work-items):
//   {
//     operation: 'create' | 'update' | 'transition' | 'delete',
//     // --- create ---
//     project?: 'PWI',                 // default PWI
//     issueType?: 'Requirement',       // default Requirement
//     fieldsExtra?: { ... },           // custom fields ya en shape Jira (customfield_xxx)
//     summary?, problema, contexto?, impacto?, resultado_esperado,
//     urgencia?, area?, thread_url, priority_id?,
//     // --- update ---
//     issueKey?, fields?: { ... },     // objeto Jira (assignee, priority, summary, ...)
//     // --- transition ---
//     transitionId?, comment?,
//     // --- delete ---
//     confirm?: true
//   }
// Respuesta sincrona: { ok, operation, issueKey?, issueUrl?, error? }
// ============================================================================

const body = $input.first().json.body || {};
const op = (body.operation || '').toLowerCase();

const fail = (msg) => [{ json: { _valid: false, _error: msg, operation: op } }];

const VALID_OPS = ['create', 'update', 'transition', 'delete', 'search'];
if (!VALID_OPS.includes(op)) {
  return fail(`operation invalida o ausente: "${op}". Validas: ${VALID_OPS.join(', ')}`);
}

// --- Validacion por operacion ----------------------------------------------
if (op === 'create') {
  if (!body.problema)           return fail('create requiere "problema"');
  if (!body.resultado_esperado) return fail('create requiere "resultado_esperado"');
  if (!body.thread_url)         return fail('create requiere "thread_url"');
}
if (op === 'update') {
  if (!body.issueKey) return fail('update requiere "issueKey"');
  if (!body.fields || typeof body.fields !== 'object') return fail('update requiere "fields" (objeto Jira)');
}
if (op === 'transition') {
  if (!body.issueKey)     return fail('transition requiere "issueKey"');
  if (!body.transitionId) return fail('transition requiere "transitionId"');
}
if (op === 'delete') {
  if (!body.issueKey)        return fail('delete requiere "issueKey"');
  if (body.confirm !== true) return fail('delete requiere "confirm": true (guarda anti-borrado)');
}

if (op === 'search') {
  if (!body.jql) return fail('search requiere "jql"');
}

// --- Passthrough normalizado ------------------------------------------------
return [{ json: { ...body, operation: op, _valid: true } }];

// ============================================================================
// Build Create Body — UNICA fuente del formato ADF + campos de creacion.
// Esquema verificado contra Jira real (2026-06-04):
//   - issuetype Requirement = id 10155 (proyecto PWI / PRODUCT 10168)
//   - Business Area  = customfield_10310 (select) IDs 10128-10133
//   - Discussion Thread = customfield_10311 (url)
//   - Intake Type    = customfield_10312 (select) Discussion=10134 Manual=10135
// Reemplaza la logica duplicada y DESACTUALIZADA de:
//   - conversation-handler · Code — Build Jira Body
//   - approval-handler      · Rebuild Jira Payload (usaba cf_10170 + IDs 10020-24, obsoletos)
// ============================================================================

const b = $json;
const clean = (s) => (s || '').replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ').trim() || '-';

const project       = b.project   || 'PWI';
const issueTypeId   = b.issueTypeId || '10155';       // Requirement
const priority_id   = b.priority_id || '3';           // Medium

// --- Business Area: mapa nombre -> id (IDs reales Jira) ---------------------
const AREA_NAME_TO_ID = {
  'Finance & Accounting': '10128',
  'Legal & Compliance':   '10129',
  'Operations':           '10130',
  'Sales & Partnerships': '10131',
  'Trading Desk':         '10132',
  'Management':           '10133',
};
// Acepta business_area_id directo, o lo resuelve desde area (nombre)
let businessAreaId = b.business_area_id || (b.area ? AREA_NAME_TO_ID[b.area] : '') || '';

// --- Intake Type: Discussion (10134) por defecto para capturas de Slack -----
//   override con b.intake_type_id si el caller lo necesita distinto
const intakeTypeId = b.intake_type_id || '10134';     // Discussion

// --- Summary ---------------------------------------------------------------
let summary = b.summary;
if (!summary) {
  const probClean = clean(b.problema);
  const raw = '[Miles] ' + (b.area ? b.area + ' \u2014 ' : '') + probClean;
  summary = raw.length > 150 ? raw.substring(0, raw.lastIndexOf(' ', 150)) + '\u2026' : raw;
}

// --- ADF description (formato fiel) -----------------------------------------
const desc = {
  type: 'doc', version: 1,
  content: [
    { type: 'paragraph', content: [{ type: 'text', text: 'Capturado por Miles via Slack', marks: [{ type: 'em' }] }] },
    ...(b.thread_url ? [
      { type: 'paragraph', content: [{ type: 'text', text: '\ud83d\udd17 Ver hilo en Slack', marks: [{ type: 'link', attrs: { href: b.thread_url } }] }] }
    ] : []),
    { type: 'rule' },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Problema' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(b.problema) }] },
    ...(clean(b.contexto) !== '-' ? [
      { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Contexto' }] },
      { type: 'paragraph', content: [{ type: 'text', text: clean(b.contexto) }] }
    ] : []),
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Impacto' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(b.impacto) }] },
    { type: 'heading', attrs: { level: 3 }, content: [{ type: 'text', text: 'Resultado esperado' }] },
    { type: 'paragraph', content: [{ type: 'text', text: clean(b.resultado_esperado) }] },
    { type: 'rule' },
    { type: 'paragraph', content: [{ type: 'text', text: 'Urgencia: ' + clean(b.urgencia || 'Normal') }] }
  ]
};

const fields = {
  project: { key: project },
  issuetype: { id: issueTypeId },
  summary,
  priority: { id: priority_id },
  description: desc,
};

// Business Area (select)
if (businessAreaId) fields.customfield_10310 = { id: businessAreaId };
// Discussion Thread (url) — ademas del link en el ADF
if (b.thread_url) fields.customfield_10311 = b.thread_url;
// Intake Type (select)
if (intakeTypeId) fields.customfield_10312 = { id: intakeTypeId };

// Custom fields extra ya en shape Jira (override / casos especiales)
if (b.fieldsExtra && typeof b.fieldsExtra === 'object') {
  Object.assign(fields, b.fieldsExtra);
}

return [{ json: { jira_body: JSON.stringify({ fields }), _op: 'create' } }];

// Normaliza la respuesta sincrona del handler.
const op = $('Validate & Route').first().json.operation;

// search -> devuelve issues crudos de Jira
if (op === 'search') {
  const r = $json || {};
  const issues = r.issues || [];
  return [{ json: { ok: true, operation: op, total: issues.length, issues } }];
}

// resto de operaciones -> issueKey / issueUrl
let issueKey = '', issueUrl = '';
try {
  const r = $json;
  issueKey = r.key || r.issueKey || $('Validate & Route').first().json.issueKey || '';
} catch (e) {}
if (issueKey) issueUrl = 'https://arduasolutions.atlassian.net/browse/' + issueKey;
return [{ json: { ok: true, operation: op, issueKey, issueUrl } }];
